import{_ as a,o,c as s,ae as l}from"./chunks/framework.CL3pmU-5.js";const e="/ComputerNetwork/assets/%E5%88%86%E7%BB%84%E4%BA%A4%E6%8D%A2.TkwEC8j8.svg",i="/ComputerNetwork/assets/%E7%BD%91%E7%BB%9C%E6%A0%B8%E5%BF%83.wXDSoUuB.svg",h=JSON.parse('{"title":"1.3 网络核心","description":"","frontmatter":{},"headers":[],"relativePath":"第一章/1.3 网络核心.md","filePath":"第一章/1.3 网络核心.md"}'),r={name:"第一章/1.3 网络核心.md"};function p(c,t,n,_,d,u){return o(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="_1-3-网络核心" tabindex="-1">1.3 网络核心 <a class="header-anchor" href="#_1-3-网络核心" aria-label="Permalink to &quot;1.3 网络核心&quot;">​</a></h1><h2 id="老旧技术-电路交换" tabindex="-1">老旧技术 （电路交换） <a class="header-anchor" href="#老旧技术-电路交换" aria-label="Permalink to &quot;老旧技术 （电路交换）&quot;">​</a></h2><p>网络核心主要目的：将源目标主机发送的信息传送给目标主机。</p><p>在过去，我们有一种老旧的技术叫：<strong>电路交换</strong>来实现网络核心的功能。其工作原理类似于电视剧中出现的播电话，然后接线员将其接通。</p><p>那么一条线路只给一个人用，太过于浪费，于是有了:<strong>频分</strong>，<strong>时分</strong>，<strong>波分</strong></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>将网络资源（如带宽）分成片的技术不同，叫频/时/波 分</p></div><p>但电路交换还是有很大的缺点：</p><ol><li>建立连接时间长</li><li>浪费的片较多</li><li>可靠性不高</li></ol><h2 id="现代技术-分组转发" tabindex="-1">现代技术 （分组转发） <a class="header-anchor" href="#现代技术-分组转发" aria-label="Permalink to &quot;现代技术 （分组转发）&quot;">​</a></h2><p>数据被拆成一段一段（分成一组一组），然后通过每一个交换节点就存储，然后转发。</p><p><img src="'+e+'" alt="分组交换"></p><p>这样的<strong>好处</strong>：存储转发，资源共享，按需要使用。</p><p>在某一个节点处：到达速率 &gt; 链路的输出速率</p><ul><li>分组将会排队，等待传输完</li><li>如果路由器的缓存用完了，分组将会被抛弃</li></ul><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>那为什么缓存不设置无线大呢？</p></div><p><strong>关键功能</strong>：</p><ol><li>路由：决定分组采用的源到目标的路径</li><li>转发：将分组从路由器的输入链路转移到输出链路</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>日常中使用网络，都是突发的，这里指的是我们浏览的时间比发送请求的时间长的多。</p><p>电路交换中：会一直占用一个链路，浪费的资源多； 分组交换中：来数据就分组转发，不会一直占用一条链路。</p><p>所以分组转发适合于网络的突发性。</p></div><h2 id="不同的寻路方式" tabindex="-1">不同的寻路方式 <a class="header-anchor" href="#不同的寻路方式" aria-label="Permalink to &quot;不同的寻路方式&quot;">​</a></h2><p>我们按照网络层有没有连接分为</p><ul><li>数据报方式：携带了目标主机的完整地址，不需要握手（路径不一样，可能会失序）</li><li>虚电路：需要先建立连接，虚电路号来标识</li></ul><p><img src="'+i+'" alt="网络核心"></p>',22)])])}const g=a(r,[["render",p]]);export{h as __pageData,g as default};
